example.code:
{
  "__faion_header__": {
    "methodology": "vui-conversation-design",
    "version": "1.1.0",
    "produces": "spec"
  },
  "states": [
    {
      "id": "ask-date",
      "allowed_intents": [
        "provide-date"
      ],
      "voice_script": "Which date works for you?",
      "screen_prompt": "Select a date below or say one out loud.",
      "no_match_handler": "reprompt-1: 'I didn't catch that.'",
      "ambiguous_handler": "ask user to disambiguate"
    },
    {
      "id": "confirm",
      "allowed_intents": [
        "confirm",
        "deny"
      ],
      "voice_script": "Book for Tuesday at 3 PM. Confirm?",
      "screen_prompt": "Confirm booking for Tuesday at 3 PM (Yes / No)",
      "no_match_handler": "reprompt-1: 'Say yes or cancel.'",
      "ambiguous_handler": "reprompt: 'Sorry, was that yes or cancel?'"
    }
  ],
  "reprompt_cap": 3,
  "noise_test_conditions": [
    "quiet",
    "ambient",
    "kitchen"
  ]
}

{
  "states": [
    {
      "id": "x",
      "voice_script": "Please proceed to provide the date for your appointment booking confirmation"
    }
  ],
  "reprompt_cap": 7,
  "noise_test_conditions": [
    "quiet"
  ]
}
